mapper.select:
SELECT COUNT(*) FROM ( SELECT i.inbound_id, CASE WHEN SUM(ii.quantity) = 0 THEN '미입고' WHEN SUM(ii.quantity) >= SUM(moi.quantity) THEN '입고완료' ELSE '부분입고' END AS status FROM material_inbound i LEFT JOIN material_inbound_item ii ON i.inbound_id = ii.inbound_id LEFT JOIN material m ON ii.material_id = m.material_id LEFT JOIN material_order_item moi ON i.order_id = moi.order_id AND moi.material_id = ii.material_id GROUP BY i.inbound_id
HAVING 1=1
AND status = #{status}
) AS inbound_status
